package com.example.bookservice.controller;import com.example.bookservice.exception.ExceptionController;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.Exchange;import com.example.bookservice.model.ExchangeAdminStatsDto;import com.example.bookservice.service.ExchangeService;import com.fasterxml.jackson.databind.ObjectMapper;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.http.HttpStatus;import org.springframework.http.MediaType;import org.springframework.test.web.servlet.MockMvc;import org.springframework.test.web.servlet.setup.MockMvcBuilders;import java.time.LocalDateTime;import java.util.ArrayList;import java.util.Collections;import java.util.List;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.anyLong;import static org.mockito.ArgumentMatchers.anyString;import static org.mockito.Mockito.doNothing;import static org.mockito.Mockito.doThrow;import static org.mockito.Mockito.when;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;@ExtendWith(MockitoExtension.class)class ExchangeControllerTest {  private MockMvc mockMvc;  private ObjectMapper objectMapper;  @Mock private ExchangeService exchangeService;  @InjectMocks private ExchangeController exchangeController;  private Exchange exchange;  @BeforeEach  void setUp() {    objectMapper = new ObjectMapper();    objectMapper.findAndRegisterModules();    mockMvc =        MockMvcBuilders.standaloneSetup(exchangeController)            .setControllerAdvice(new ExceptionController())            .build();    exchange = new Exchange();    exchange.setId(1L);    exchange.setInitiator("user1");    exchange.setRecipient("user2");    exchange.setBookInitiator("Book1");    exchange.setBookRecipient("Book2");    exchange.setCreatedAt(LocalDateTime.now());    exchange.setStatus("wait");  }  @Test  void createExchange_ReturnCreated() throws Exception {    doNothing().when(exchangeService).addExchange(any(Exchange.class));    mockMvc        .perform(            post("/exchanges")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(exchange)))        .andExpect(status().isCreated());  }  @Test  void createExchange_ReturnConflict() throws Exception {    doThrow(new HttpStatusException(HttpStatus.CONFLICT, "Данный обмен уже существует!"))        .when(exchangeService)        .addExchange(any(Exchange.class));    mockMvc        .perform(            post("/exchanges")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(exchange)))        .andExpect(status().isConflict())        .andExpect(jsonPath("$.message").value("Данный обмен уже существует!"));  }  @Test  void createExchange_ReturnNotFound() throws Exception {    doThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Книга с названием Book1 не существует"))        .when(exchangeService)        .addExchange(any(Exchange.class));    mockMvc        .perform(            post("/exchanges")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(exchange)))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Книга с названием Book1 не существует"));  }  @Test  void getExchangesByInitiator_ReturnListOfExchanges() throws Exception {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeService.getExchangesByInitiator("user1")).thenReturn(exchanges);    mockMvc        .perform(get("/exchanges/initiator/user1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].initiator").value("user1"));  }  @Test  void getExchangesByInitiator_ReturnEmptyArray() throws Exception {    when(exchangeService.getExchangesByInitiator("user1")).thenReturn(new ArrayList<>());    mockMvc        .perform(get("/exchanges/initiator/user1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$").isArray())        .andExpect(jsonPath("$").isEmpty());  }  @Test  void getExchangesByRecipient_ReturnListOfExchanges() throws Exception {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeService.getExchangesByRecipient("user2")).thenReturn(exchanges);    mockMvc        .perform(get("/exchanges/recipient/user2"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].recipient").value("user2"));  }  @Test  void getExchangesByRecipient_ReturnEmptyArray() throws Exception {    when(exchangeService.getExchangesByRecipient("user2")).thenReturn(new ArrayList<>());    mockMvc        .perform(get("/exchanges/recipient/user2"))        .andExpect(status().isOk())        .andExpect(jsonPath("$").isArray())        .andExpect(jsonPath("$").isEmpty());  }  @Test  void getLastExchanges_ReturnListOfExchanges() throws Exception {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeService.getExchangesByDescCreatedAt()).thenReturn(exchanges);    mockMvc        .perform(get("/exchanges/last"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L));  }  @Test  void getExchangeAdminStats_ReturnStats() throws Exception {    ExchangeAdminStatsDto statsDto = new ExchangeAdminStatsDto(5L, 2L, 40);    when(exchangeService.getExchangeStatsForAdmin()).thenReturn(statsDto);    mockMvc        .perform(get("/exchanges/stats"))        .andExpect(status().isOk())        .andExpect(jsonPath("$.countExchanges").value(5L))        .andExpect(jsonPath("$.countSuccessExchanges").value(2L))        .andExpect(jsonPath("$.percentSuccess").value(40));  }  @Test  void cancelExchange_ReturnNoContent() throws Exception {    doNothing().when(exchangeService).deleteExchange(1L);    mockMvc.perform(delete("/exchanges/1")).andExpect(status().isNoContent());  }  @Test  void cancelExchange_ReturnNotFound() throws Exception {    doThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Обмен с id 1 не найден!"))        .when(exchangeService)        .deleteExchange(1L);    mockMvc        .perform(delete("/exchanges/1"))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Обмен с id 1 не найден!"));  }  @Test  void updateStatus_ReturnOk() throws Exception {    doNothing().when(exchangeService).changeStatus(anyLong(), anyString());    mockMvc        .perform(patch("/exchanges/1/status").param("status", "done"))        .andExpect(status().isOk());  }  @Test  void updateStatus_ReturnBadRequest() throws Exception {    doThrow(new HttpStatusException(HttpStatus.BAD_REQUEST, "Неверный статус: invalid"))        .when(exchangeService)        .changeStatus(anyLong(), anyString());    mockMvc        .perform(patch("/exchanges/1/status").param("status", "invalid"))        .andExpect(status().isBadRequest())        .andExpect(jsonPath("$.message").value("Неверный статус: invalid"));  }  @Test  void updateStatus_ReturnNotFound() throws Exception {    doThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Обмен с id=1 не найден"))        .when(exchangeService)        .changeStatus(anyLong(), anyString());    mockMvc        .perform(patch("/exchanges/1/status").param("status", "done"))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Обмен с id=1 не найден"));  }}